section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/core-vui-design-principles.json",
  "title": "Core VUI Design Principles",
  "type": "object",
  "required": [
    "artefact_id",
    "skill_id",
    "prompts_audited",
    "simplicity_score",
    "naturalness_score",
    "context_score",
    "violations",
    "reviewer",
    "overall_verdict",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "skill_id": {
      "type": "string",
      "description": "skill_id",
      "minLength": 1
    },
    "prompts_audited": {
      "type": "array",
      "description": "prompts_audited (array)",
      "minItems": 1
    },
    "simplicity_score": {
      "type": "number",
      "description": "simplicity_score (numeric)"
    },
    "naturalness_score": {
      "type": "number",
      "description": "naturalness_score (numeric)"
    },
    "context_score": {
      "type": "number",
      "description": "context_score (numeric)"
    },
    "violations": {
      "type": "array",
      "description": "violations (array)",
      "minItems": 1
    },
    "reviewer": {
      "type": "string",
      "description": "reviewer",
      "minLength": 1
    },
    "overall_verdict": {
      "type": "string",
      "description": "overall_verdict",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
